import os
import shutil

def recursive_delete(directory, ignore_dir=None):
    """
    Recursively deletes all files and directories in the given directory.

    Args:
        directory (str): The path to the directory to delete.
        ignore_dir (str, optional): The path to a directory to ignore. Defaults to None.

    Raises:
        FileNotFoundError: If the directory does not exist.
        PermissionError: If the script lacks permission to delete a file or directory.
    """
    if not os.path.exists(directory):
        print(f"The directory '{directory}' does not exist.")
        return

    if ignore_dir and os.path.samefile(directory, ignore_dir):
        print(f"Ignoring directory '{directory}' as per your request.")
        return

    for item in os.listdir(directory):
        item_path = os.path.join(directory, item)
        if os.path.isdir(item_path):
            recursive_delete(item_path, ignore_dir)
            try:
                shutil.rmtree(item_path)
            except PermissionError:
                print(f"Permission denied to delete directory '{item_path}'.")
        else:
            try:
                os.remove(item_path)
            except PermissionError:
                print(f"Permission denied to delete file '{item_path}'.")

